import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.math.BigDecimal;
import java.math.RoundingMode;

/**
 * LOCKER - a group-REDEFINES program, translated from COBOL 85. Idiomatic
 * variant: flattens the redefined record into named fields.
 *
 * Reads the member record (4-digit id, balance in cents), applies the
 * money view over the record, charges a 2.5% late fee ROUNDED and tiers
 * balances over 200.00 as GOLD.
 */
public final class Locker {

    private static final BigDecimal RATE = new BigDecimal("25");
    private static final BigDecimal THOUSAND = new BigDecimal("1000");
    private static final BigDecimal THRESHOLD = new BigDecimal("200");
    private static final BigDecimal PIC_9_4 = new BigDecimal("10000");
    private static final BigDecimal PIC_9_6 = new BigDecimal("1000000");
    private static final BigDecimal PIC_9_4_V99 = new BigDecimal("10000");
    private static final BigDecimal PIC_9_5_V99 = new BigDecimal("100000");

    public static void main(String[] args) throws IOException {
        BufferedReader in = new BufferedReader(new InputStreamReader(System.in));

        BigDecimal memId = numval(in.readLine(), PIC_9_4);
        BigDecimal cents = numval(in.readLine(), PIC_9_6);

        // The money view over the record: key and dollars.
        BigDecimal memKey = memId;
        BigDecimal dollars = memId.movePointLeft(2);

        BigDecimal fee = dollars.multiply(RATE).divide(THOUSAND).setScale(2, RoundingMode.HALF_UP).remainder(PIC_9_4_V99);
        BigDecimal total = dollars.add(fee).remainder(PIC_9_5_V99);
        String tier = dollars.compareTo(THRESHOLD) > 0 ? "GOLD" : "STD ";

        StringBuilder out = new StringBuilder();
        out.append("KEY=").append(memKey.setScale(0, RoundingMode.UNNECESSARY).toPlainString()).append('\n');
        out.append("FEE=").append(fee.setScale(2, RoundingMode.UNNECESSARY).toPlainString()).append('\n');
        out.append("TOTAL=").append(total.setScale(2, RoundingMode.UNNECESSARY).toPlainString()).append('\n');
        out.append("TIER=").append(tier).append('\n');
        System.out.print(out);
    }

    private static BigDecimal numval(String s, BigDecimal capacity) {
        try {
            return new BigDecimal(s.trim()).setScale(0, RoundingMode.DOWN).remainder(capacity);
        } catch (NumberFormatException e) {
            System.err.println("LOCKER: invalid numeric input: " + s);
            System.exit(3);
            return BigDecimal.ZERO;
        }
    }
}
